const Q_PHYSICS_2017_MODEL_II=[{"id": "objective>Physics>2017 Model II>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A hand bag containing some load weighing 162N is carried by two students each holding the handle of the bag that is next to him. If each handle is pulled 60° to the vertical, find the force on each students arm.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">162N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">398N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">420N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">500N</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2017 Model II/661xja.png\" style=\"position:relative;max-width:100%;\"/> <br/> NB: F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = F <br/> Sum of forces in the vertical direction, <br/> Fcos60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> + Fcos60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> = 162 <br/> 2Fcos60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> = 162 <br/> 2F &#215; 0.5 = 162 <br/> ∴ F = 162N</div>", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES"}, {"id": "objective>Physics>2017 Model II>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When water condenses on the surface of a cup of cold water placed on a table, the temperature of the surrounding air </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decreases slightly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases slightly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remains unchanged </div>", "<div style=\"font-family:Cambria;font-size:17px;\">first decreases and then increases </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">As the water condenses, heat of vaporization is evolved, which warms the surrounding air. Note that this is the exact opposite of the process of evaporation resulting in the cooling of the surroundings.</div>", "topic": "CHANGE OF STATE : SPECIFIC LATENT HEATS OF VAPORIZATION"}, {"id": "objective>Physics>2017 Model II>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following units is derived?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Kg is the unit of mass , m is the unit of length , k is unit of temperature and N is the unit of force. Amongst these, force is the only derived quantity</div>", "topic": "MEASUREMENTS AND UNITS : DERIVED PHYSICAL QUANTITIES AND THEIR UNITS"}, {"id": "objective>Physics>2017 Model II>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The quality of a musical note depends on what?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">frequency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">loudness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">harmonics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">echo</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The quality of a musical note, also known as timbre, is determined by the harmonics of the sound. Harmonics are the overtones of a note that exist due to the physical properties of the instrument producing the sound. They give each instrument its unique sound quality. Frequency determines the pitch of the note, loudness is the amplitude of the sound wave, and echo is a reflection of sound that arrives at the listener some time after the direct sound.</div>", "topic": "CHARACTERISTICS OF SOUND WAVES : QUALITY, PITCH, INTENSITY AND LOUDNESS"}, {"id": "objective>Physics>2017 Model II>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The diagrams below illustrate four test-tubes containing the same volume of a liquid at different pressures. In which of the test-tubes does the liquid boil last if they are supplied with the same quantity of heat?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2017 Model II/up6eq6.png\" style=\"position:relative;max-width:100%;\"/> <br/> The boiling point of a liquid depends on both temperature and pressure. Generally, an increase in pressure raises the boiling point, while a decrease in pressure lowers it. Therefore, if the four test tubes contain the same volume of liquid and are supplied with the same quantity of heat, the liquid in the test tube with a higher pressure will boil last. <br/>  <br/> In this case, the test tube with 2 atm of pressure will cause the liquid to boil last compared to the test tube with <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2</span> atm of pressure. This is because higher pressure increases the boiling point of the liquid, requiring more heat to reach the boiling point compared to lower pressure conditions.</div>", "topic": "CHANGE OF STATE : EFFECT OF PRESSURE AND IMPURITIES ON BOILING AND MELTING POINTS"}, {"id": "objective>Physics>2017 Model II>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">At which of the following temperatures will a given mass of water occupy the greatest volume?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">80°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100°C</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The volume of a given mass of water is smallest at 4°C, but the volume thereafter increases with temperature until the boiling point (100°C) is reached.</div>", "topic": "THERMAL EXPANSION : LIQUIDS"}, {"id": "objective>Physics>2017 Model II>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A gas would serve as an electrical conductor under </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reduced pressure and reduced potential difference </div>", "<div style=\"font-family:Cambria;font-size:17px;\">exposure to light</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduced pressure and high potential difference </div>", "<div style=\"font-family:Cambria;font-size:17px;\">high pressure and high potential difference</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A gas can serve as an electrical conductor under reduced pressure and high potential difference. This is because under high potential difference, the gas molecules get ionized and start conducting electricity. Reduced pressure allows the free movement of these ionized particles, thus facilitating conduction.</div>", "topic": "CONDUCTION OF ELECTRICITY THROUGH : GASES"}, {"id": "objective>Physics>2017 Model II>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object of mass 10kg initially at rest on a horizontal surface is subjected to a horizontal force of 40N. The body moves in the direction of the applied force with an acceleration of 3ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>. The work done against friction after moving the object for two seconds is ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">240J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">180J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">120J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60J</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The applied force of 40N is used in overcoming friction and ingiving the object an acceleration. <br/> Force accelerating the object = ma = 10(3) = 30N <br/> Frictional force = 40 - 30 = 10N <br/> After 2s, the object is moved through distance  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">s</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">at<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">(3)(2)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6m</td></tr></table></div> <br/> Workdone against friction = frictional force × distance  <br/> = 10 × 6 = 60J</div>", "topic": "WORK, ENERGY AND POWER"}, {"id": "objective>Physics>2017 Model II>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the tension in a sonometer is tripled, the ratio of the new frequency to the original frequency is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1/3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It should be noted that; frequency F is directly proportional to the square root of tension, &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T&nbsp;</span> <br/> F α &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T&nbsp;</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>&nbsp;</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>&nbsp;</span></td><td style=\"text-align:center;\">------</td><td style=\"text-align:center;\">*</td></tr></table></div> <br/> The tension is trippled, i.e <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 3T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>&nbsp;</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span></td></tr></table></div> <br/> The ratio of the new frequrncy to the original frequency i.e <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span><hr size=\"1\" />1</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span></td></tr></table></div></div>", "topic": "WAVES : PRODUCTION AND PROPAGATION"}, {"id": "objective>Physics>2017 Model II>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A person in a room feels cooler under a rotating fan because the fan</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lowers the room temperature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases the rate of evaporation from the skin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduced the relative humidity in the room</div>", "<div style=\"font-family:Cambria;font-size:17px;\">blows cooler air to the skin</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The skin feels cooler as the rate of evaporation from its surface increases. The room temperature and relative humidity do not change appreciably, and the blown air is at room temperature.</div>", "topic": "HEAT TRANSFER"}, {"id": "objective>Physics>2017 Model II>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A man stands on a scale in a lift which descends with an acceleration of g/5, where g is the acceleration due to gravity. If the man's true weight is W, the reading on the scale is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.2W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.9W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.8W</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reading on the scale is the reaction R. Newton's second law: <br/> mg - R = ma <br/> R = m(g - a) = m(g - g/5) <br/>  = 0.8mg or 0.8W <br/> </div>", "topic": "MOTION : NEWTON’S LAWS OF MOTION~~MOTION: MOTION UNDER GRAVITY"}, {"id": "objective>Physics>2017 Model II>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A man moves 4km southward, then 5 km westward and finally 4km Northward. The displacement of the man is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5km Eastward</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5Km Westward</div>", "<div style=\"font-family:Cambria;font-size:17px;\">13km Eastward </div>", "<div style=\"font-family:Cambria;font-size:17px;\">13km Westward</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diagrammatically, <br/> <img src=\"2017 Model II/i7o3o6.png\" style=\"position:relative;max-width:100%;\"/> <br/> Displacement, D = 5km westwards</div>", "topic": "SCALARS AND VECTORS"}, {"id": "objective>Physics>2017 Model II>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> If the above system is at equilibrium, the values of T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> and T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">50&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span>csc 75° and 50&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2&nbsp;</span> csc 75°</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2&nbsp;</span>csc 75° and 50&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span> csc 75° <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">50&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span>csc 15° and 50&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2&nbsp;</span> csc 15° <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">None of the above</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2017 Model II/jtv6yg.png\" style=\"position:relative;max-width:100%;\"/> <br/> <img src=\"2017 Model II/iaat1f.png\" style=\"position:relative;max-width:100%;\"/> <br/> <img src=\"2017 Model II/o23iyi.png\" style=\"position:relative;max-width:100%;\"/> <br/> 100 = T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>cos60° <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">100<hr size=\"1\" />cos60°</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">200N</td></tr></table></div> <br/> 100N = T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>sin45° <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 100/sin45° = 100 ÷ 1/&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2&nbsp;</span> = 100&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2&nbsp;</span> N <br/> Therefore, none of the options is correct</div>", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES"}, {"id": "objective>Physics>2017 Model II>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A fixed mass of gas is compressed isothermally and its volume is appreciably reduced. Which of the following statements is (are) correct about the gas? <br/> I. The average kinetic energy of its molecules is increased  <br/> II. The rare of molecular collisions is increased <br/> III. The average inter-molecular spacing is reduced </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Since the gas is compressed isothermally (i.e at constant temperature) the average k.e of its molecules remains constant. However, the molecules are packed into a smaller space after compression, hence, both the average spacing between molecules and the number of molecular collisions per unit time increase. </div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>2017 Model II>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The mass of the earth is 6.0 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">24</span>kg and that of the moon is 7.3 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">22</span>kg. If the distance between them is 4.0 ×  10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>m. Find the force of attraction between them [G = 6.7 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-11</span> Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>kg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.8 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.8 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">10</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.8 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">15</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.8 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">20</span>N</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The gravitational force between two bodies is calculated using the formula F = G * (m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> * m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) / r<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>. Substituting the given values into the formula, we get F = 6.7 * 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-11</span> * (6.0 * 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">24</span> * 7.3 * 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">22</span>) / (4.0 * 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 1.8 * 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">20</span> N.</div>", "topic": "GRAVITATIONAL FIELD"}, {"id": "objective>Physics>2017 Model II>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a wind instrument?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Harp</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Violin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Trombone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gong</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A wind instrument is a musical instrument that produces sound by the vibration of air, typically through the player blowing into it. Among the given options, the Trombone is a wind instrument.</div>", "topic": "CHARACTERISTICS OF SOUND WAVES : FREQUENCY OF A NOTE EMITTED BY AIR COLUMNS"}, {"id": "objective>Physics>2017 Model II>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most suitable instrument for measuring the diameter of a thin wire accurately is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a metre rule</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a pair of vernier callipers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a micrometer screw gauge </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a ruler </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Since the wire is thin, a micrometer screw gauge which is capable of measurements to the nearest 0.001cm is most suitable.</div>", "topic": "MEASUREMENTS AND UNITS : LENGTH, AREA AND VOLUME"}, {"id": "objective>Physics>2017 Model II>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A body is whirled round a circular path at constant speed. Which of the following diagrams correctly indicates the direction of the body's velocity (v) and acceleration (a)?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For a body undergoing circular motion, the acceleration is directed towards the centre, and the velocity is directed round the circumference of the circle as we have as below. <br/> <img src=\"2017 Model II/5o69em.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "MOTION: MOTION IN A CIRCLE"}, {"id": "objective>Physics>2017 Model II>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements about matter is not correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Molecules of solids move more freely than molecules of liquids and gases </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Molecules of solids are more closely packed than those of the liquids </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Energy is required to break the intermolecular forces of attraction between molecules</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Molecules of liquids move about within the liquid and they are in constant random motion</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The molecules of gases move with the highest speed, followed by the molecules of liquid and then solids.</div>", "topic": "STRUCTURE OF MATTER AND KINETIC THEORY : KINETIC THEORY"}, {"id": "objective>Physics>2017 Model II>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The unit cycle per second is the same as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">watt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">metres per second</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hertz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">radians per second</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The unit 'cycle per second' is the same as 'hertz'. Both are units of frequency, which measures the number of occurrences of a repeating event per unit of time. The term 'cycle per second' was largely replaced by 'hertz' in the 1960s.</div>", "topic": "WAVES : PRODUCTION AND PROPAGATION"}, {"id": "objective>Physics>2017 Model II>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The pressure applied to an enclosed fluid at one end is transmitted equally throughout the fluid and of the container walls. This statement is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Archimede's principle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bernoulli's principle </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pascal's principle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Heisenberg's uncertainty principle </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pascal's law (also Pascal's principle or the principle of transmission of fluid-pressure) is a principle in fluid mechanics that states that a pressure change occurring anywhere in a confined incompressible fluid is transmitted throughout the fluid such that the same change occurs everywhere.</div>", "topic": "PRESSURE : PRESSURE IN LIQUIDS"}, {"id": "objective>Physics>2017 Model II>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One advantage of connecting electric cells in parallel is that the effective</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">emf is increased </div>", "<div style=\"font-family:Cambria;font-size:17px;\">internal resistance is decreased </div>", "<div style=\"font-family:Cambria;font-size:17px;\">emf is decreased</div>", "<div style=\"font-family:Cambria;font-size:17px;\">internal resistance is increased </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The effective emf of n identical cells connected in parallel is equal to the emf of any one of them. However, the effective internal resistance is rln, where r is the internal resistance of each cell.</div>", "topic": "ELECTRIC CELLS : ARRANGEMENT OF CELLS"}, {"id": "objective>Physics>2017 Model II>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A simple pendulum makes 90 oscillations in one minute on the earth's surface. The number of oscillations per minute which the same pendulum will execute at an altitude where the acceleration due to gravity is 81 percent of its value on earth is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">73</div>", "<div style=\"font-family:Cambria;font-size:17px;\">81</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100</div>", "<div style=\"font-family:Cambria;font-size:17px;\">111</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2π</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">g<hr size=\"1\" />L</td><td style=\"text-align:center;\">&nbsp;</span></td><td style=\"text-align:center;\">on</td><td style=\"text-align:center;\">the</td><td style=\"text-align:center;\">earth's</td><td style=\"text-align:center;\">surface</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2π</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">0.81g<hr size=\"1\" />L</td><td style=\"text-align:center;\">&nbsp;</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.9f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">at</td><td style=\"text-align:center;\">the</td><td style=\"text-align:center;\">altitude.</td></tr></table></div> <br/> Hence, f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 0.9 × 90 = 81 oscillations per minute</div>", "topic": "MOTION: SIMPLE HARMONIC MOTION (S.H.M)"}, {"id": "objective>Physics>2017 Model II>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A glass flask has a capacity of 500cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> at 100°C. If the coefficient of linear expansion of glass is 3.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>C<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, the capacity of the flask at 30°C is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">500.336cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">500.112cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">499.888cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">499.664cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Coefficient of cubical expansion of glass = 3.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> × 3 = 9.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>C<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> In reducing the temperature from 100°C to 30°C, the volume of the flask decreases by an amount  <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span>γθ = 500(9.6 ×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>)(100 - 30) = 0.336cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Volume at 30°C = 500 - 0336 = 499.664cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "THERMAL EXPANSION : SOLIDS"}, {"id": "objective>Physics>2017 Model II>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is Power?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Force × time</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Force × distance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Force × acceleration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Force × velocity</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">Energy<hr size=\"1\" />Time</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Power</td><td style=\"text-align:center;\">-----------</td><td style=\"text-align:center;\">(1)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Force × displacement<hr size=\"1\" />Time</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Power</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Power</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Force</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">displacement<hr size=\"1\" />time</td></tr></table></div> <br/> Power = Force × velocity</div>", "topic": "WORK, ENERGY AND POWER: POWER"}, {"id": "objective>Physics>2017 Model II>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An automobile travelling at a speed of 20ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> is brought uniformly to a halt in 10 seconds when a braking force of 5kN is applied. The mass of the automobile  is ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1,000 kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1,500 kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2,000 kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2,500 kg</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Acceleration, a = (v-u)/t = (0-20)/10 = -2ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">m</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<hr size=\"1\" />a</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5000<hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2,5000kg</td></tr></table></div></div>", "topic": "MOTION : NEWTON’S LAWS OF MOTION"}, {"id": "objective>Physics>2017 Model II>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The resultant force in a couple is ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">zero</div>", "<div style=\"font-family:Cambria;font-size:17px;\">infinite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the sum of the forces </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the product of the forces </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A couple is a pair of forces, equal in magnitude, oppositely directed, and displaced by some distance. This means the forces are balanced and hence their resultant force is zero. Therefore, the correct option is 'zero'.</div>", "topic": "EQUILIBRIUM OF FORCES : EQUILIBRIUM OF PARTICLES"}, {"id": "objective>Physics>2017 Model II>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A rainbow is formed when sunlight is incident on water droplets suspended in the air due to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">diffraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">refraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dispersion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">interference</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rainbow is  a consequence of dispersion of light. These colors are often observed as light passes through a triangular prism. Upon passage through the prism, the white light is separated into its component colors - red, orange, yellow, green, blue and violet. The separation of visible light into its different colors is known as dispersion.</div>", "topic": "DISPERSION OF LIGHT AND COLOURS"}, {"id": "objective>Physics>2017 Model II>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A bullet is fired at an angle of 60° to the vertical with a speed of 50m/s. Determine its maximum height reached  <br/> [Take g = 10m/s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">31.25m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">62.50m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">93.75m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">125.0m</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span> = 30° (since it is 60° to the vertical) <br/> u = 50ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">max</span> = ? ; g = 10m/s <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">max</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">u<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>sin<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>θ<hr size=\"1\" />2g</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">max</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">(50)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>(sin<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>30)<hr size=\"1\" />2g</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">max</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2500×0.25<hr size=\"1\" />20</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">625<hr size=\"1\" />50</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">31.25m</td></tr></table></div></div>", "topic": "MOTION: PROJECTILES"}, {"id": "objective>Physics>2017 Model II>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The volume of a bubble is doubled as it rises from the bottom to the top of a lake. If the atmospheric pressure is equivalent to 10.3m of water, the depth of the lake is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5.15m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10.3m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20.6m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30.9m</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The (air) bubble increases in size as it rises through the lake because of the decreasing pressure (PV) = constant). The pressure at the surface must be one -half of the pressure at the bottom of the lake. Hence, pressure at the bottom of the lake = 2 × 10.3 = 20.6m = atmospheric + 10.3m. <br/> This is the pressure at a depth of 10.3m of water.</div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>2017 Model II>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two bodies have masses in the ratio 3:1. They experience forces which imparts to them acceleration in the ratio 2:9 respectively. Find the ratio of forces the masses experienced.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1:4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2:3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2:5</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3<hr size=\"1\" />1</td><td style=\"text-align:center;\"></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">a<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />a<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />9</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Unknown</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>a<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>a<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3×2<hr size=\"1\" />1×9</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6<hr size=\"1\" />9</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />3</td></tr></table></div></div>", "topic": "MOTION : NEWTON’S LAWS OF MOTION"}, {"id": "objective>Physics>2017 Model II>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A slide of width 2.5cm is positioned 5.0cm from the lens of a projector. If the width of the image is 100cm, the distance from the lens to the screen is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">40cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">200cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">250cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">500cm</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Magnification,</td><td style=\"text-align:center;\">m</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">100<hr size=\"1\" />2.5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">40</td></tr></table></div> <br/> Distance from the lens to the screen is  <br/> v = mu = 40(5) = 200cm <br/> </div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>2017 Model II>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A body accelerates uniformly from rest for a time t. The kinetic energy of the body at t <br/> I. is directly proportional to the displacement  <br/> II. is directly proportional to the square of the instantaneous velocity <br/> III. is directly proportional to t<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> IV. depends on the value of the acceleration <br/> Which of the above statements is (are) correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II, III and IV</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Since v<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 2as and v = at, we can write  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">K.E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">mv<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">m(2as)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">m(at)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">ma<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>t<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> .e the K.E is directly proportional to s and to t<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> and it also depends on the acceleration a.</div>", "topic": "WORK, ENERGY AND POWER"}, {"id": "objective>Physics>2017 Model II>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A constant-volume gas thermometer operates under which gas law?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Boyle's law </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Charles' law</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Avogadro's law</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pressure law</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A constant-volume gas thermometer operates under the pressure law, which states that the pressure of a gas at constant volume is directly proportional to its temperature.</div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>2017 Model II>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A 2kW immersion heater is used to heat 1kg of water initially at a temperature of 20°C. How much water will boil away in 3 minutes? [specific heat capacity of water = 4.2 kJkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>°C<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, specific latent heat of vaporization of water = 2.4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> kJkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">140g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">150g</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Heat needed to raise the temperature of water from 20°C to 100°C = mcθ = 1(4.2)(80) = 336kJ <br/> Heat supplied by the 2kW heater in 3 minutes. <br/>  = 2(kJ/s) × 3 × 60(s) 360kJ <br/> The difference, 360 - 336 = 24kJ is used in boiling off m kg of water. <br/> Hence, 24 = mL<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">v</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">or</td><td style=\"text-align:center;\">m</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">24<hr size=\"1\" />(2.4×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>kg</td><td style=\"text-align:center;\">or</td><td style=\"text-align:center;\">10g</td></tr></table></div></div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>2017 Model II>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A body of mass 1,000kg is released from a height of 10m above the ground. Determine its kinetic energy just before it strikes the ground. [g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>J</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">K.E = P.E = mgh <br/>  <br/> = 1000 × 10 × 10  <br/>  <br/> = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span> Joules</div>", "topic": "WORK ENERGY AND POWER : CONSERVATION OF ENERGY"}, {"id": "objective>Physics>2017 Model II>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two masses separated by a distance (d) attract each other with a gravitational force of 12N. If the separation between the masses is reduced to d/2, the gravitational force will </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase to 48N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase to 24N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease to 6N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease to 3N</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Gm<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />d<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">12N</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">With</td><td style=\"text-align:center;\">the</td><td style=\"text-align:center;\">distance</td><td style=\"text-align:center;\">between</td><td style=\"text-align:center;\">the</td><td style=\"text-align:center;\">bodies</td><td style=\"text-align:center;\">reduced</td><td style=\"text-align:center;\">to</td><td style=\"text-align:center;\">d<hr size=\"1\" />2,</td><td style=\"text-align:center;\">the</td><td style=\"text-align:center;\">new</td><td style=\"text-align:center;\">gravitational</td><td style=\"text-align:center;\">force</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">attraction</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Gm<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />(d<hr size=\"1\" />2)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4Gm<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />d<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span></td></tr></table></div> <br/> = 4 × 12 = 48N</div>", "topic": "GRAVITATIONAL FIELD"}, {"id": "objective>Physics>2017 Model II>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The dimension of Newton's gravitational constant is M<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">x</span>L<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">z</span>, the value of x+y/z is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-2</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall: From Newton's Law of Universal Gravitation <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">GM<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />r<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">G</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Fr<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">G</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">MLT<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>×L<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />M<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> G = M<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>L<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/> Equate this to M<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">x</span>L<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">z</span> <br/> M<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">x</span>L<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">z</span> = M<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>L<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/> x = -1, y = 3 and z = -2 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">x+y<hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">-1+3<hr size=\"1\" />-2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />-2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">-1</td></tr></table></div></div>", "topic": "MEASUREMENTS AND UNITS : DIMENSIONS"}, {"id": "objective>Physics>2017 Model II>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The effect of increased pressure on the transformation temperatures of water is that the  <br/> I. melting point is reduced <br/> II. melting point is increased <br/> III. boiling point is reduced <br/> IV. boiling point is increased <br/> Which of the above statements are correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and IV only</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct statements are: <br/>  <br/> I. Melting point is reduced <br/> IV. Boiling point is increased <br/>  <br/> Melting Point: Water expands when it freezes, meaning that applying pressure favors the liquid state over the solid. This causes the melting point to decrease under increased pressure. <br/>  <br/> Boiling Point: Higher pressure makes it harder for water molecules to escape into the gas phase, so the boiling point increases as pressure rises. <br/>  <br/> Thus, the correct answer is I and IV.</div>", "topic": "CHANGE OF STATE : EFFECT OF PRESSURE AND IMPURITIES ON BOILING AND MELTING POINTS"}, {"id": "objective>Physics>2017 Model II>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">At which of the following temperatures will a given mass of water occupy the greatest volume?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">80°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100°C</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The volume of a given mass of water is smallest at 4°C, but the volume thereafter increases with temperature until the boiling point (100°C) is reached.</div>", "topic": "THERMAL EXPANSION : LIQUIDS"}];
